<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">ofp = </span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">self</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.config.max_head_offpolicyness</span></span>
